def meny():
  val = "" #Kommentera bort den här raden så får du UnboundLocalError
  while val != "2":
    print("Meny\n1. Val 1.\n2. Avsluta.")
    val = input("Vad vill du göra?")
    if val == "1":
      print("Du valde 1.\n")

    elif val == "2":
      print("Programmet avslutas")

    else:
       print("Inte ett menyval, välj igen.")

meny()
